import React, { useEffect, useState } from "react";
import {
  getOverview,
  getAllRiders,
  getCaptains,
  getPendingCaptains,
  getAllRides,
  approveRider,
  rejectRider,
  getSOSAlerts,
  resolveSOS,
} from "../../services/api";
import { useAuth } from "../../contexts/AuthContext";
import {
  AppBar,
  Toolbar,
  Box,
  Typography,
  Button,
  CircularProgress,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  Card,
  CardMedia,
  CardActions,
  Grid,
  Paper,
  Tabs,
  Tab,
  Stack,
  Link,
  Dialog,
  DialogTitle,
  DialogContent,
} from "@mui/material";

import GroupsIcon from "@mui/icons-material/Groups";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import HourglassTopIcon from "@mui/icons-material/HourglassTop";
import CommuteIcon from "@mui/icons-material/Commute";
import PersonIcon from "@mui/icons-material/Person";
import WarningAmberIcon from "@mui/icons-material/WarningAmber";

export default function AdminDashboard() {
  const { logout } = useAuth();

  const [overview, setOverview] = useState({
    users: 0,
    captains: 0,
    pendingCaptains: 0,
    rides: 0,
    riders: 0,
    sos: 0,
  });

  const [activeTab, setActiveTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Documents modal state
  const [openDocsModal, setOpenDocsModal] = useState(false);
  const [selectedDocuments, setSelectedDocuments] = useState([]);
  const [selectedRider, setSelectedRider] = useState(null);
  const [selectedRiderName, setSelectedRiderName] = useState("");

  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data.data || {});

      const sosRes = await getSOSAlerts();
      setOverview((prev) => ({
        ...prev,
        sos: sosRes.data?.data?.filter((s) => s.status === "active").length || 0,
      }));
    } catch (err) {
      console.error(err);
      setError("Failed to load overview");
    }
  };

  const fetchData = async (type) => {
    setActiveTab(type);
    setLoading(true);
    setError("");
    try {
      let res;
      switch (type) {
        case "users":
        case "riders":
          res = await getAllRiders();
          break;
        case "captains":
          res = await getCaptains();
          break;
        case "pending":
          res = await getPendingCaptains();
          break;
        case "rides":
          res = await getAllRides();
          break;
        case "sos":
          res = await getSOSAlerts();
          break;
        default:
          res = { data: { data: [] } };
      }
      // Helpful for debugging: uncomment to inspect API shape
      // console.log(type, res?.data?.data);
      setData(res?.data?.data || []);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data");
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id) => {
    try {
      await approveRider(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to approve rider");
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectRider(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to reject rider");
    }
  };

  const handleResolveSOS = async (id) => {
    try {
      await resolveSOS(id);
      fetchData("sos");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to resolve SOS");
    }
  };

  // Helper to resolve relative URLs (backend) to full URLs if needed
  const resolveUrl = (u) => {
    if (!u) return "";
    if (/^https?:\/\//i.test(u)) return u;
    const prefix = (process.env.REACT_APP_API_URL || "").replace(/\/$/, "");
    if (!prefix) return u;
    return `${prefix}${u.startsWith("/") ? u : "/" + u}`;
  };

  // Documents modal handlers
  const handleViewDocuments = (item) => {
    const rawDocs = item?.documents || [];
    let docsArr = [];

    if (Array.isArray(rawDocs)) {
      docsArr = rawDocs;
    } else if (rawDocs && typeof rawDocs === "object") {
      // convert object-of-files to array (handles different backend shapes)
      docsArr = Object.keys(rawDocs).map((k) => rawDocs[k]);
    }

    setSelectedDocuments(docsArr);
    setSelectedRider(item || null);
    setSelectedRiderName(item?.fullName || item?.name || "");
    setOpenDocsModal(true);
  };

  const handleCloseDocuments = () => {
    setOpenDocsModal(false);
    setSelectedDocuments([]);
    setSelectedRider(null);
    setSelectedRiderName("");
  };

  useEffect(() => {
    fetchOverview();
  }, []);

  const cards = [
    { label: "Users", value: overview.users, icon: <GroupsIcon />, type: "users", color: "#3498db" },
    { label: "Riders", value: overview.riders, icon: <PersonIcon />, type: "riders", color: "#1abc9c" },
    { label: "Approved Captains", value: overview.captains, icon: <VerifiedUserIcon />, type: "captains", color: "#2ecc71" },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <HourglassTopIcon />, type: "pending", color: "#e67e22" },
    { label: "Rides", value: overview.rides, icon: <CommuteIcon />, type: "rides", color: "#9b59b6" },
    { label: "SOS Alerts", value: overview.sos, icon: <WarningAmberIcon />, type: "sos", color: "#e74c3c" },
  ];

  const renderDocumentsCell = (item) => {
    const documents = item?.documents;
    const empty =
      !documents ||
      (Array.isArray(documents) && documents.length === 0) ||
      (!Array.isArray(documents) && Object.keys(documents).length === 0);

    if (empty) return "-";

    return (
      <Button variant="outlined" size="small" onClick={() => handleViewDocuments(item)}>
        View Documents
      </Button>
    );
  };

  const renderActionsCell = (item) => (
    <Stack direction="row" spacing={1} justifyContent="center">
      <Button size="small" color="success" variant="outlined" onClick={() => handleApprove(item._id)}>
        Approve
      </Button>
      <Button size="small" color="error" variant="outlined" onClick={() => handleReject(item._id)}>
        Reject
      </Button>
    </Stack>
  );

  return (
    <Box sx={{ flexGrow: 1, bgcolor: "#f4f6f8", minHeight: "100vh" }}>
      {/* Header */}
      <AppBar position="static" sx={{ bgcolor: "#34495e", mb: 4 }}>
        <Toolbar sx={{ display: "flex", justifyContent: "space-between" }}>
          <Typography variant="h6" fontWeight="bold">
            Admin Dashboard
          </Typography>
          <Button variant="contained" color="error" onClick={logout}>
            Logout
          </Button>
        </Toolbar>
      </AppBar>

      <Box maxWidth="1300px" mx="auto" px={3} pb={5}>
        {/* Tabs */}
        <Paper elevation={3} sx={{ borderRadius: 3, mb: 4 }}>
          <Tabs
            value={activeTab}
            onChange={(e, val) => {
              setData([]);
              val === "overview" ? fetchOverview() : fetchData(val);
              setActiveTab(val);
            }}
            indicatorColor="primary"
            textColor="primary"
            variant="fullWidth"
            sx={{ "& .MuiTab-root": { fontWeight: 600, fontSize: "14px" } }}
          >
            <Tab label="Overview" value="overview" />
            <Tab label="Users" value="users" />
            <Tab label="Riders" value="riders" />
            <Tab label="Approved Captains" value="captains" />
            <Tab label="Pending Captains" value="pending" />
            <Tab label="Rides" value="rides" />
            <Tab label="SOS Alerts" value="sos" />
          </Tabs>
        </Paper>

        {/* Overview Cards */}
        {activeTab === "overview" && (
          <Grid container spacing={3}>
            {cards.map((card) => (
              <Grid item xs={12} sm={6} md={3} key={card.label}>
                <Card
                  sx={{
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                    p: 2,
                    borderRadius: 3,
                    boxShadow: 3,
                    transition: "0.3s",
                    "&:hover": { boxShadow: 6, transform: "translateY(-5px)" },
                  }}
                  onClick={() => card.type !== "overview" && fetchData(card.type)}
                >
                  <Box>
                    <Typography variant="subtitle1" fontWeight="bold" color={card.color}>
                      {card.label}
                    </Typography>
                    <Typography variant="h4" fontWeight="bold" color={card.color}>
                      {card.value}
                    </Typography>
                  </Box>
                  <Box sx={{ fontSize: 50, color: card.color }}>{card.icon}</Box>
                </Card>
              </Grid>
            ))}
          </Grid>
        )}

        {/* Loading/Error */}
        {loading && (
          <Box display="flex" justifyContent="center" mt={4}>
            <CircularProgress />
          </Box>
        )}
        {error && (
          <Typography color="error" textAlign="center" mt={2}>
            {error}
          </Typography>
        )}

        {/* Data Tables */}
        {!loading && data.length > 0 && activeTab !== "overview" && activeTab !== "sos" && (
          <Paper sx={{ p: 3, borderRadius: 3, boxShadow: 3, mt: 4, overflowX: "auto" }}>
            <Typography variant="h6" mb={2} fontWeight="bold">
              {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} Details
            </Typography>
            <Table>
              <TableHead>
                <TableRow sx={{ bgcolor: "#ecf0f1" }}>
                  <TableCell sx={{ fontWeight: 600 }}>Name</TableCell>
                  <TableCell sx={{ fontWeight: 600 }}>Email</TableCell>
                  <TableCell sx={{ fontWeight: 600 }}>Mobile</TableCell>
                  <TableCell sx={{ fontWeight: 600 }}>Role</TableCell>
                  {(activeTab === "captains" || activeTab === "pending") && (
                    <TableCell sx={{ fontWeight: 600 }}>Documents</TableCell>
                  )}
                  {activeTab === "pending" && (
                    <TableCell sx={{ fontWeight: 600, textAlign: "center" }}>Actions</TableCell>
                  )}
                  {activeTab === "rides" && (
                    <>
                      <TableCell sx={{ fontWeight: 600 }}>Rider</TableCell>
                      <TableCell sx={{ fontWeight: 600 }}>Captain</TableCell>
                      <TableCell sx={{ fontWeight: 600 }}>Pickup</TableCell>
                      <TableCell sx={{ fontWeight: 600 }}>Drop</TableCell>
                      <TableCell sx={{ fontWeight: 600 }}>Status</TableCell>
                    </>
                  )}
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((item) => (
                  <TableRow key={item._id} hover sx={{ "&:nth-of-type(odd)": { bgcolor: "#fafafa" } }}>
                    <TableCell>{item.fullName || "-"}</TableCell>
                    <TableCell>{item.email || "-"}</TableCell>
                    <TableCell>{item.mobile || "-"}</TableCell>
                    <TableCell>{item.role || "-"}</TableCell>

                    {(activeTab === "captains" || activeTab === "pending") && (
                      <TableCell>{renderDocumentsCell(item)}</TableCell>
                    )}

                    {activeTab === "pending" && <TableCell align="center">{renderActionsCell(item)}</TableCell>}

                    {activeTab === "rides" && (
                      <>
                        <TableCell>{item.riderId?.fullName || "-"}</TableCell>
                        <TableCell>{item.captainId?.fullName || "-"}</TableCell>
                        <TableCell>{item.pickup || "-"}</TableCell>
                        <TableCell>{item.drop || "-"}</TableCell>
                        <TableCell>{item.status || "-"}</TableCell>
                      </>
                    )}
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Paper>
        )}

        {/* Documents Modal */}
        <Dialog open={openDocsModal} onClose={handleCloseDocuments} maxWidth="md" fullWidth>
          <DialogTitle>Documents - {selectedRiderName}</DialogTitle>
          <DialogContent dividers>
            {/* Rider details */}
            {selectedRider ? (
              <Box mb={2}>
                <Typography>
                  <strong>Name:</strong> {selectedRider.fullName || "-"}
                </Typography>
                <Typography>
                  <strong>Email:</strong> {selectedRider.email || "-"}
                </Typography>
                <Typography>
                  <strong>Mobile:</strong> {selectedRider.mobile || "-"}
                </Typography>
                <Typography>
                  <strong>Role:</strong> {selectedRider.role || "-"}
                </Typography>
                <Typography>
                  <strong>Status:</strong> {selectedRider.approvalStatus || selectedRider.status || "-"}
                </Typography>
                <Typography>
                  <strong>Created:</strong>{' '}
                  {selectedRider.createdAt ? new Date(selectedRider.createdAt).toLocaleString() : "-"}
                </Typography>
              </Box>
            ) : null}

            <Typography variant="h6" gutterBottom>
              Documents
            </Typography>

            {(!selectedDocuments || selectedDocuments.length === 0) ? (
              <Typography>No documents uploaded.</Typography>
            ) : (
              <Stack spacing={2} direction="row" flexWrap="wrap">
                {selectedDocuments.map((doc, idx) => {
                  // doc can be a string (url) or object { url, filename, mimetype, location, path, secure_url }
                  const url = doc?.url || doc?.location || doc?.path || doc?.secure_url || (typeof doc === 'string' ? doc : null);
                  const finalUrl = resolveUrl(url);
                  const filename = doc?.filename || doc?.originalname || doc?.name || finalUrl?.split('/')?.pop() || `Document ${idx + 1}`;
                  const isImage = /\.(jpe?g|png|gif|webp|bmp|svg)$/i.test(finalUrl || "") || (doc?.mimetype && /image\//i.test(doc.mimetype));

                  return (
                    <Card key={idx} sx={{ width: 300 }}>
                      {isImage ? (
                        <CardMedia component="img" height="180" image={finalUrl} alt={filename} sx={{ objectFit: "contain" }} />
                      ) : (
                        <Box sx={{ height: 180, display: "flex", alignItems: "center", justifyContent: "center" }}>
                          <Typography>{filename}</Typography>
                        </Box>
                      )}

                      <CardActions>
                        <Button size="small" onClick={() => window.open(finalUrl, "_blank")}>View</Button>
                        <Link sx={{ ml: 1 }} href={finalUrl} target="_blank" rel="noopener noreferrer">Open</Link>
                      </CardActions>
                    </Card>
                  );
                })}
              </Stack>
            )}
          </DialogContent>
        </Dialog>

        {/* SOS Alerts Table */}
        {activeTab === "sos" && !loading && (
          <Paper sx={{ p: 3, borderRadius: 3, boxShadow: 3, mt: 4, overflowX: "auto" }}>
            <Typography variant="h6" mb={2} fontWeight="bold">
              SOS Alerts
            </Typography>
            <Table>
              <TableHead>
                <TableRow sx={{ bgcolor: "#ecf0f1" }}>
                  <TableCell>User/Rider</TableCell>
                  <TableCell>Role</TableCell>
                  <TableCell>Time</TableCell>
                  <TableCell>Status</TableCell>
                  <TableCell>Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((sos) => (
                  <TableRow key={sos._id} hover>
                    <TableCell>{sos.userId?.fullName || "-"}</TableCell>
                    <TableCell>{sos.role}</TableCell>
                    <TableCell>{new Date(sos.createdAt).toLocaleString()}</TableCell>
                    <TableCell>{sos.status}</TableCell>
                    <TableCell>
                      {sos.status === "active" && (
                        <Button size="small" color="success" variant="outlined" onClick={() => handleResolveSOS(sos._id)}>
                          Resolve
                        </Button>
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Paper>
        )}

        {!loading && data.length === 0 && activeTab !== "overview" && (
          <Typography textAlign="center" mt={3}>No data found</Typography>
        )}
      </Box>
    </Box>
  );
}
